// src/commands/_hookStop.ts
var HOOK_TIMEOUT_MS = 3e3;
var READ_RETRY_DELAYS_MS = [250, 500, 750];
async function runHookStop() {
  const config = await loadConfig();
  if (!config) return;
  const transcriptPath = await transcriptPathFromStdin() ?? await findMostRecentTranscript();
  if (!transcriptPath) return;
  let lines = await readRateLimitLines(transcriptPath);
  for (let i = 0; lines.length === 0 && i < READ_RETRY_DELAYS_MS.length; i++) {
    await sleep2(READ_RETRY_DELAYS_MS[i]);
    lines = await readRateLimitLines(transcriptPath);
  }
  if (lines.length === 0) return;
  const detection = detectRateLimit(lines);
  if (!detection) return;
  const { reset_at } = detection;
  const idempotency_key = idempotencyKeyFor(reset_at);
  const apiBase = resolvedApiBase(config);
  const state = await loadState();
  if (state.pending_submit.length > 0) {
    await flushPending(state, config, apiBase);
  }
  const alreadyDone = state.submitted.some((e) => e.idempotency_key === idempotency_key) || state.pending_submit.some((e) => e.idempotency_key === idempotency_key);
  if (alreadyDone) {
    await saveState(state);
    return;
  }
  try {
    const res = await post(
      NotifyResponseSchema,
      `${apiBase}/v1/notify`,
      { reset_at_unix: reset_at, idempotency_key },
      config.device_token,
      HOOK_TIMEOUT_MS
    );
    if (res.status === "scheduled" || res.status === "duplicate") {
      state.submitted.push({
        idempotency_key,
        submitted_at: Math.floor(Date.now() / 1e3),
        reset_at
      });
    }
  } catch (err) {
    state.pending_submit.push({
      idempotency_key,
      reset_at,
      last_error: err instanceof Error ? err.message : String(err)
    });
  }
  await saveState(state);
}
async function flushPending(state, config, apiBase) {
  const nowSec = Math.floor(Date.now() / 1e3);
  const stillPending = [];
  for (const entry of state.pending_submit) {
    if (entry.reset_at < nowSec - 3600) continue;
    if (state.submitted.some((e) => e.idempotency_key === entry.idempotency_key)) continue;
    try {
      const res = await post(
        NotifyResponseSchema,
        `${apiBase}/v1/notify`,
        {
          reset_at_unix: entry.reset_at,
          idempotency_key: entry.idempotency_key
        },
        config.device_token,
        HOOK_TIMEOUT_MS
      );
      if (res.status === "scheduled" || res.status === "duplicate") {
        state.submitted.push({
          idempotency_key: entry.idempotency_key,
          submitted_at: nowSec,
          reset_at: entry.reset_at
        });
      } else {
        stillPending.push(entry);
      }
    } catch {
      stillPending.push({ ...entry });
    }
  }
  state.pending_submit = stillPending;
}
function sleep2(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

