// src/redact.ts
var TOKEN_RE = /\b[A-Za-z0-9_-]{43}\b/g;
var BOT_TOKEN_RE = /\b\d{8,12}:[A-Za-z0-9_-]{30,}\b/g;
function redact(text) {
  return text.replace(TOKEN_RE, "[REDACTED]").replace(BOT_TOKEN_RE, "[REDACTED]");
}

